function stripHtml(html: string): string {
  return html
    .replace(/<[^>]*>/g, "")
    .replace(/\\r\\\\n/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 180);
}

